codeExercises.solution:
const moveCardToDifferentColumnWithTransaction = async (data) => {
  const { 
    cardId, 
    sourceColumnId, 
    destinationColumnId, 
    sourceCardOrderIds, 
    destinationCardOrderIds 
  } = data;

  const session = await mongoose.startSession();

  try {
    await session.withTransaction(async () => {
      await columnModel.updateOne(
        { _id: sourceColumnId },
        { $set: { cardOrderIds: sourceCardOrderIds } },
        { session }
      );

      await columnModel.updateOne(
        { _id: destinationColumnId },
        { $set: { cardOrderIds: destinationCardOrderIds } },
        { session }
      );

      await cardModel.updateOne(
        { _id: cardId },
        { $set: { columnId: destinationColumnId } },
        { session }
      );
    });

    return { message: 'Card moved successfully with transaction!' };
  } catch (error) {
    // `withTransaction` sẽ tự động abort nếu có lỗi, nên ta chỉ cần throw lại lỗi
    throw error;
  } finally {
    await session.endSession();
  }
};
